///     Manage their own view lifecycle
///   </li>
///   <li>
///     May react to layout or context changes
///   </li>
/// </ul>
/// <h2>Responsibilities</h2>
/// <ul>
///   <li>
///     Provide a <code>UIView</code> representation for rendering
///   </li>
///   <li>
///     Handle context/lifecycle changes (e.g. screen transitions, resizing)
///   </li>
///   <li>
///     Forward media lifecycle events (e.g. video completion)
///   </li>
/// </ul>
/// <h2>Notes</h2>
/// <ul>
///   <li>
///     The returned view from <code>createUIView()</code> is owned by the SDK
///     unless otherwise documented by the implementation.
